		.io_enq_valid(fire),
		.io_enq_bits_data(_GEN_0[choice * 1024+:1024]),
		.io_enq_bits_strobe(_GEN_1[choice * 128+:128]),
		.io_enq_bits_keep(_GEN_2[choice * 128+:128]),
		.io_enq_bits_last(_GEN_3[choice]),
		.io_enq_bits_dest(_GEN_4[choice * 4+:4]),
		.io_deq_ready(io_sink_ready),
		.io_deq_valid(io_sink_valid),
		.io_deq_bits_data(io_sink_bits_data),
