	input W0_en;
	input W0_clk;
	input [511:0] W0_data;
	reg [511:0] Memory [0:255];
	always @(posedge W0_clk)
		if (W0_en & 1'h1)
			Memory[W0_addr] <= W0_data;
	assign R0_data = (R0_en ? Memory[R0_addr] : 512');
