	io_deq_bits_last,
	io_deq_bits_dest
);
	input clock;
	input reset;
	output wire io_enq_ready;
	input io_enq_valid;
	input [1031:0] io_enq_bits_data;
	input [128:0] io_enq_bits_strobe;
	input [128:0] io_enq_bits_keep;
	input io_enq_bits_last;
	input [3:0] io_enq_bits_dest;
	input io_deq_ready;
	output wire io_deq_valid;
	output wire [1031:0] io_deq_bits_data;
	output wire [128:0] io_deq_bits_strobe;
	output wire [128:0] io_deq_bits_keep;
	output wire io_deq_bits_last;
	output wire [3:0] io_deq_bits_dest;
	wire [1294:0] _ram_ext_R0_data;
	reg wrap;
	reg wrap_1;
	reg maybe_full;
	wire ptr_match = wrap == wrap_1;
	wire empty = ptr_match & ~maybe_full;
	wire full = ptr_match & maybe_full;
	wire do_enq = ~full & io_enq_valid;
	always @(posedge clock)
		if (reset) begin
			wrap <= 1'h0;
			wrap_1 <= 1'h0;
			maybe_full <= 1'h0;
		end
		else begin : sv2v_autoblock_1
			reg do_deq;
			do_deq = io_deq_ready & ~empty;
			if (do_enq)
				wrap <= wrap - 1'h1;
			if (do_deq)
				wrap_1 <= wrap_1 - 1'h1;
			if (~(do_enq == do_deq))
				maybe_full <= do_enq;
		end
	ram_2x1295 ram_ext(
		.R0_addr(wrap_1),
		.R0_en(1'h1),
		.R0_clk(clock),
		.R0_data(_ram_ext_R0_data),
		.W0_addr(wrap),
		.W0_en(do_enq),
		.W0_clk(clock),
		.W0_data({io_enq_bits_dest, io_enq_bits_last, io_enq_bits_keep, io_enq_bits_strobe, io_enq_bits_data})
	);
	assign io_enq_ready = ~full;
	assign io_deq_valid = ~empty;
	assign io_deq_bits_data = _ram_ext_R0_data[1031:0];
	assign io_deq_bits_strobe = _ram_ext_R0_data[1160:1032];
	assign io_deq_bits_keep = _ram_ext_R0_data[1289:1161];
	assign io_deq_bits_last = _ram_ext_R0_data[1290];
	assign io_deq_bits_dest = _ram_ext_R0_data[1294:1291];
endmodule
