	output wire io_deq_bits_last;
	output wire [3:0] io_deq_bits_dest;
	wire [644:0] _ram_ext_R0_data;
	reg [6:0] enq_ptr_value;
	reg [6:0] deq_ptr_value;
	reg maybe_full;
	wire ptr_match = enq_ptr_value == deq_ptr_value;
	wire empty = ptr_match & ~maybe_full;
	wire full = ptr_match & maybe_full;
	wire do_enq = ~full & io_enq_valid;
	always @(posedge clock)
		if (reset) begin
			enq_ptr_value <= 7'h00;
			deq_ptr_value <= 7'h00;
			maybe_full <= 1'h0;
		end
		else begin : sv2v_autoblock_1
			reg do_deq;
			do_deq = io_deq_ready & ~empty;
			if (do_enq)
				enq_ptr_value <= enq_ptr_value + 7'h01;
			if (do_deq)
				deq_ptr_value <= deq_ptr_value + 7'h01;
			if (~(do_enq == do_deq))
				maybe_full <= do_enq;
		end
	ram_128x645 ram_ext(
		.R0_addr(deq_ptr_value),
		.R0_en(1'h1),
		.R0_clk(clock),
		.R0_data(_ram_ext_R0_data),
		.W0_addr(enq_ptr_value),
		.W0_en(do_enq),
		.W0_clk(clock),
		.W0_data({io_enq_bits_dest, io_enq_bits_last, io_enq_bits_keep, io_enq_bits_strobe, io_enq_bits_data})
	);
	assign io_enq_ready = ~full;
	assign io_deq_valid = ~empty;
	assign io_deq_bits_data = _ram_ext_R0_data[511:0];
	assign io_deq_bits_strobe = _ram_ext_R0_data[575:512];
	assign io_deq_bits_keep = _ram_ext_R0_data[639:576];
	assign io_deq_bits_last = _ram_ext_R0_data[640];
	assign io_deq_bits_dest = _ram_ext_R0_data[644:641];
endmodule
module ram_128x4 (
	R0_addr,
	R0_en,
	R0_clk,
	R0_data,
	W0_addr,
	W0_en,
	W0_clk,
	W0_data
);
	input [6:0] R0_addr;
	input R0_en;
	input R0_clk;
	output wire [3:0] R0_data;
	input [6:0] W0_addr;
	input W0_en;
	input W0_clk;
	input [3:0] W0_data;
	reg [3:0] Memory [0:127];
	always @(posedge W0_clk)
		if (W0_en & 1'h1)
			Memory[W0_addr] <= W0_data;
	assign R0_data = (R0_en ? Memory[R0_addr] : 4'bxxxx);
endmodule
module Queue128_UInt4 (
	clock,
	reset,
	io_enq_ready,
	io_enq_valid,
	io_enq_bits,
	io_deq_ready,
	io_deq_valid,
	io_deq_bits
);
	input clock;
	input reset;
	output wire io_enq_ready;
	input io_enq_valid;
	input [3:0] io_enq_bits;
	input io_deq_ready;
	output wire io_deq_valid;
	output wire [3:0] io_deq_bits;
	reg [6:0] enq_ptr_value;
	reg [6:0] deq_ptr_value;
	reg maybe_full;
	wire ptr_match = enq_ptr_value == deq_ptr_value;
	wire empty = ptr_match & ~maybe_full;
	wire full = ptr_match & maybe_full;
	wire do_enq = ~full & io_enq_valid;
	always @(posedge clock)
		if (reset) begin
			enq_ptr_value <= 7'h00;
			deq_ptr_value <= 7'h00;
			maybe_full <= 1'h0;
		end
		else begin : sv2v_autoblock_1
			reg do_deq;
			do_deq = io_deq_ready & ~empty;
			if (do_enq)
				enq_ptr_value <= enq_ptr_value + 7'h01;
			if (do_deq)
				deq_ptr_value <= deq_ptr_value + 7'h01;
			if (~(do_enq == do_deq))
				maybe_full <= do_enq;
		end
	ram_128x4 ram_ext(
		.R0_addr(deq_ptr_value),
		.R0_en(1'h1),
		.R0_clk(clock),
		.R0_data(io_deq_bits),
		.W0_addr(enq_ptr_value),
		.W0_en(do_enq),
		.W0_clk(clock),
		.W0_data(io_enq_bits)
	);
	assign io_enq_ready = ~full;
	assign io_deq_valid = ~empty;
endmodule
module elasticDemux_174 (
	io_source_ready,
	io_source_valid,
	io_source_bits_data,
	io_source_bits_strobe,
	io_source_bits_keep,
	io_source_bits_last,
	io_source_bits_dest,
	io_sinks_0_ready,
	io_sinks_0_valid,
	io_sinks_0_bits_data,
	io_sinks_0_bits_strobe,
	io_sinks_0_bits_keep,
	io_sinks_0_bits_last,
	io_sinks_0_bits_dest,
	io_sinks_1_ready,
	io_sinks_1_valid,
	io_sinks_1_bits_data,
	io_sinks_1_bits_strobe,
	io_sinks_1_bits_keep,
	io_sinks_1_bits_last,
	io_sinks_1_bits_dest,
	io_select_ready,
	io_select_valid,
	io_select_bits
);
	output wire io_source_ready;
	input io_source_valid;
	input [511:0] io_source_bits_data;
	input [63:0] io_source_bits_strobe;
	input [63:0] io_source_bits_keep;
	input io_source_bits_last;
	input [3:0] io_source_bits_dest;
	input io_sinks_0_ready;
	output wire io_sinks_0_valid;
	output wire [511:0] io_sinks_0_bits_data;
	output wire [63:0] io_sinks_0_bits_strobe;
	output wire [63:0] io_sinks_0_bits_keep;
	output wire io_sinks_0_bits_last;
	output wire [3:0] io_sinks_0_bits_dest;
	input io_sinks_1_ready;
	output wire io_sinks_1_valid;
	output wire [511:0] io_sinks_1_bits_data;
	output wire [63:0] io_sinks_1_bits_strobe;
	output wire [63:0] io_sinks_1_bits_keep;
	output wire io_sinks_1_bits_last;
	output wire [3:0] io_sinks_1_bits_dest;
	output wire io_select_ready;
	input io_select_valid;
	input io_select_bits;
	wire valid = io_select_valid & io_source_valid;
	wire fire = valid & (io_select_bits ? io_sinks_1_ready : io_sinks_0_ready);
	assign io_source_ready = fire;
	assign io_sinks_0_valid = valid & ~io_select_bits;
	assign io_sinks_0_bits_data = io_source_bits_data;
	assign io_sinks_0_bits_strobe = io_source_bits_strobe;
	assign io_sinks_0_bits_keep = io_source_bits_keep;
	assign io_sinks_0_bits_last = io_source_bits_last;
	assign io_sinks_0_bits_dest = io_source_bits_dest;
	assign io_sinks_1_valid = valid & io_select_bits;
	assign io_sinks_1_bits_data = io_source_bits_data;
	assign io_sinks_1_bits_strobe = io_source_bits_strobe;
	assign io_sinks_1_bits_keep = io_source_bits_keep;
	assign io_sinks_1_bits_last = io_source_bits_last;
	assign io_sinks_1_bits_dest = io_source_bits_dest;
	assign io_select_ready = fire & io_source_bits_last;
endmodule
